module.exports = "<mat-card class=\"rounded mb-10 p-0\">\n  <mat-toolbar class=\"cdr-toolbar \">\n    <span>Notifications</span>\n  </mat-toolbar>\n  <perfect-scrollbar class=\"scroll-section h-359\" [config]=\"config\">\n    <mat-list class=\"pb25\">\n      <mat-list-item class=\"cdr-imfor\">\n         <div *ngFor=\"let item of allNotification\">\n          <!-- <div *ngIf=\"item.show\"> -->\n          <div class=\"impo-not-items\" *ngIf=\"item.dataroom_member\">\n            <i class=\"fa fa-user\"></i>\n            <h3 *ngIf=\"item.permissions\">\n              {{ item.dataroom_member.member.first_name}} was added in <span (click)=\"getToDetailedPage(item.dataroom.id)\">{{ item.dataroom_member.dataroom.dataroom_name }} </span>Data Room \n            <p>{{ item.dataroom_member.member.date_joined | date:'yyyy-dd-MM HH:mm':'timezone'}}</p>\n\n          </h3> \n\n           <h3 *ngIf=\"!item.permissions\">\n              {{ item.dataroom_member.member.first_name}} was added in <span>{{ item.dataroom_member.dataroom.dataroom_name }}</span> Data Room \n            <p>{{ item.dataroom_member.member.date_joined | date:'yyyy-dd-MM HH:mm':'timezone'}}</p>\n\n          </h3> \n          </div>\n\n          <div class=\"impo-not-items\" *ngIf=\"item.dataroom_groups\"> \n            <i class=\"fa fa-users\"></i>\n            <h3 *ngIf=\"item.permissions\"><a [routerLink]=\"['/manage-permission', item.id, 2]\">{{ item.dataroom_groups.group_name}}</a> group was added in <span (click)=\"getToDetailedPage(item.dataroom.id)\">{{ item.dataroom_groups.dataroom.dataroom_name }}</span> Data Room\n            <p>{{ item.dataroom_groups.group_created | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3> \n\n            <h3 *ngIf=\"!item.permissions\"><span>{{ item.dataroom_groups.group_name}}</span> group was added in <span>{{ item.dataroom_groups.dataroom.dataroom_name }}</span> Data Room\n            <p>{{ item.dataroom_groups.group_created | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3> \n          </div>\n\n          <div class=\"impo-not-items\" *ngIf=\"item.dataroom_folder && item.dataroom_folder.is_folder\">\n            <i class=\"fa fa-folder-open\"></i>\n            <h3 *ngIf=\"item.permissions\"><a [routerLink]=\"['/folder_detail', item.dataroom_folder.id]\">{{ item.name}}</a> Folder was added in <span (click)=\"getToDetailedPage(item.dataroom.id)\">{{ item.dataroom.dataroom_name }}</span> Data Room\n            <p>{{ item.group_created | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3> \n          </div>\n          <div class=\"impo-not-items\" *ngIf=\"item.dataroom_folder && !item.dataroom_folder.is_folder\">\n            <i class=\"fa fa-file-text\"></i>\n              <h3 *ngIf=\"item.permissions\">\n                <a href=\"{{baseUrl}}/file-view/{{item.dataroom_folder.id}}/{{user.id}}/\" (click)=\"goToViewerPage(item.dataroom_folder)\" target=\"_blank\">{{ item.dataroom_folder.name}}</a> file was added in <span (click)=\"getToDetailedPage(item.dataroom.id)\">{{ item.dataroom.dataroom_name }}</span> Data Room\n              <p>{{ item.created_date | date:'yyyy-dd-MM HH:mm':'timezone' }}</p></h3> \n              \n              <h3 *ngIf=\"!item.permissions\">\n                <span>{{ item.dataroom_folder.name}}</span> file was added in <span>{{ item.dataroom.dataroom_name }}</span> Data Room\n              <p>{{ item.created_date | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3> \n\n\n\n          </div>\n          <div class=\"impo-not-items\" *ngIf=\"item.dataroom_updates\">\n            <i class=\"fa fa-envelope\"></i>\n            <h3>{{ item.dataroom_updates.subject}} update is added in <span >{{ item.dataroom.dataroom_name }} </span> Data Room\n            <p>{{item.dataroom_updates.created_at | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3> \n          </div>\n          <div class=\"impo-not-items\" *ngIf=\"item.qna && !item.qna.answer\">\n            <!-- <div *ngIf=\"!item.qna.answer\"> -->\n              <i class=\"fa fa-question-circle\"></i>\n            <h3 *ngIf=\"item.permissions\">\n              {{ item.qna.user.first_name}} {{ item.qna.user.last}} ask the question <span (click)=\"goToQnaPage(item)\">{{item.qna.question}}</span> with the {{ item.qna.category.categories_name}} Category in <span (click)=\"getToDetailedPage(item.dataroom.id)\">{{ item.dataroom.dataroom_name }}</span> Data Room\n            <p>{{item.qna.created_at | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3> \n\n            <h3 *ngIf=\"!item.permissions\">\n              {{ item.qna.user.first_name}} {{ item.qna.user.last}} ask the question <span>{{item.qna.question}}</span> with the {{ item.qna.category.categories_name}} Category in <span>{{ item.dataroom.dataroom_name }}</span>  Data Room\n            <p>{{item.qna.created_at | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3> \n\n\n\n          <!-- </div> -->\n          </div>\n          <div class=\"impo-not-items\" *ngIf=\"item.qna && item.qna.answer\">\n            <!-- <div *ngIf=\"!item.qna.answer\"> -->\n              <i class=\"fa fa-question-circle\"></i>\n            <h3 *ngIf=\"item.permissions\">{{ item.qna.user.first_name}} {{ item.qna.user.last}} answers the question <span (click)=\"goToQnaPage(item)\">{{item.qna.question}} </span> with the {{ item.qna.category.categories_name}} Category in <span (click)=\"getToDetailedPage(item.dataroom.id)\">{{ item.dataroom.dataroom_name }}</span> Dataroom\n            <p>{{item.qna.created_at | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3>\n\n            <h3 *ngIf=\"!item.permissions\" >{{ item.qna.user.first_name}} {{ item.qna.user.last}} answers the question <span>{{item.qna.question}} </span> with the {{ item.qna.category.categories_name}} Category in <span >{{ item.dataroom.dataroom_name }}</span> Dataroom \n            <p>{{item.qna.created_at | date:'yyyy-dd-MM HH:mm':'timezone'}}</p></h3>\n\n          <!-- </div> -->\n          </div>\n\n        <!-- </div> -->\n        </div>\n        \n      </mat-list-item>\n     \n    </mat-list>\n  </perfect-scrollbar>\n  <div align=\"center\" class=\"read-more-oncard\" *ngIf=\"allNotification\"><a [routerLink]=\"['/new-notification']\" *ngIf=\"allNotification.length >= 28\">See More</a></div>\n</mat-card>\n"

