module.exports = "<app-header></app-header>\n<section id=\"cdr-body\">\n<div class=\"container-fluid\">\n  <div fxLayout=\"row\" fxLayoutAlign=\"space-between start\" fxLayoutGap=\"15px\" fxLayout.xs=\"column\" fxLayout.sm=\"column\" fxLayoutAlign.xs=\"center stretch\"\n    fxLayoutAlign.sm=\"center stretch\">\n    <!-- left side content -->\n    <aside fxFlex=\"15\">\n      <app-admin-left-side-bar [user]=\"user\">\n      </app-admin-left-side-bar>\n    </aside>\n    <!-- main content -->\n    <div fxFlex=\"85\" fxFlex.xs=\"100\" fxFlexOrder.xs=\"2\" class=\"addclass\" *ngIf=\"user.id!==''\">\n      <mat-card class=\"mat-card p0\">\n      <!-- tab nav -->\n        <mat-toolbar class=\"cdr-toolbar ad-t-bg main-container\">\n        <span routerLink=\"{{website_url}}/pay-now/{{user.id}}/{{subscription.team_id}}/\" >Manage Subscription <span class=\"no-dr\"><!-- (20) --></span></span>\n        <span fxFlex><button class=\"cdr-btn big-btn blue-btn mat-raised-button sub-exp\" routerLink=\"/subscription\">All Subscriptions</button></span>\n        <!-- <div class=\"col-md-6 mp-0 text-right\">\n          <a class=\"download-csvfile\">Download Sample Team CSV </a>\n        </div> -->\n        </mat-toolbar>\n      <mat-card>\n      <div class=\"row subs-blk\">\n        <div class=\"col-lg-4\">\n          <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n              <tr>\n                <td align=\"left\" valign=\"top\">\n                  <h6>Subscription Status</h6>\n                  <p class=\"m-0\" *ngIf=\"subscription.status\"><span style=\"color:green\">Active</span></p>\n                  <p class=\"m-0\" *ngIf=\"!subscription.status\"><span style=\"color:red\">Inactive</span></p>\n                  <!-- <p *ngIf=\"subscription.plan!=='Trial'\">Active Paid Subscription</p>\n                  <p *ngIf=\"subscription.plan==='Trial'\">Trial</p> -->\n                </td>\n              </tr>\n          </table>\n          <hr/>\n          <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n              <tr>\n                <td align=\"left\" valign=\"top\">\n                  <h6>Subscribed Plan</h6>\n                  <p class=\"m-0\">{{ subscription.plan }} <span *ngIf=\"subscription.plan!=='Trial'\"><a style=\"color:#3352ea\" (click)=\"buyOrModifyPlan()\">(Modify Plan)</a></span></p> \n                  \n                </td>\n              </tr>\n          </table>\n          <hr/>\n          <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n              <tr>\n                <td align=\"left\" valign=\"top\">\n                  <h6>Plan Details</h6>\n                 <p class=\"m-0\">Date of Activation : {{ subscription.start_date | date:'yyyy-dd-MM HH:mm':'timezone' }}</p>\n                 <p class=\"m-0\">Current billing start date : {{ subscription.start_date }}</p>\n                 <p class=\"m-0\">Expires on : {{ subscription.end_date | date:'yyyy-dd-MM HH:mm':'timezone' }}</p>\n                  <p class=\"m-0\" *ngIf=\"subscription.auto_renew==='1'\"><a (click)=\"cancelOnExpiry()\">Cancel on expiry date</a></p>\n                </td>\n              </tr>\n          </table>\n          <hr/>\n          <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n              <tr>\n                <td align=\"left\" valign=\"top\">\n                  <h6>Auto Renewal Date</h6>\n                </td>\n              </tr>\n          </table>\n          <hr/>\n           <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n              <tr>\n                <td align=\"left\" valign=\"top\">\n                  <h6>Addons</h6>\n                  <p class=\"m-0\">Data DVD</p>\n                  <p class=\"m-0\">Additional Data Room</p>\n                  <p class=\"m-0\">Additional Storage</p>\n                  <p class=\"m-0\">Compliance DVD</p>\n                </td>\n              </tr>\n          </table>\n\n        \n        </div>\n        <div class=\"col-lg-8\">\n          <div class=\"special-note\">\n            <p>The subscription will auto renewal until cancelled by the customer.</p>\n            <p>The customer should either take a back up of data by themselves or should request for a data archive from Docully.</p>\n            <p>Data / Data Room once deleted, cannot be reinstated under any circumstances.</p>\n            <p>The Data / Data Room will be qued for deletion at the end of their cancellation date and shall be available for 15 days for any re-instation requests.</p>\n            <p>If the customer doesnt want to auto renew, the customer should click on Cancel Now or Cancel on expiry date to put an end date to their active subscription.</p>\n            <p>The customer shall modify package if they anticipate a higher data storage on their subscription. If the plan is not modified, the data additional data storage fee of $50 per GB per month will be charged to the customer until the additional storage is removed from the data room before the expiry of current billing month.</p>\n          </div>\n          <div class=\"agree-chk\">\n            <mat-checkbox class=\"agree-chk\">Agree to Terms of Paid Subscription</mat-checkbox>\n          </div>\n          \n          <div class=\"btns\" style=\"text-align:left\">\n            <button class=\"cdr-btn big-btn blue-btn mat-raised-button\" *ngIf=\"subscription.plan==='Trial' && subscription.status\">Convert to Paid Subscription</button>\n            <button class=\"cdr-btn big-btn blue-btn mat-raised-button\" (click)=\"buyOrModifyPlan()\" *ngIf=\"subscription.plan!=='Trial'\">Renew Manually</button>\n            <button class=\"cdr-btn big-btn blue-btn mat-raised-button\" *ngIf=\"subscription.plan==='Trial' && subscription.status\">Cancel Trial</button>\n            <button class=\"cdr-btn big-btn blue-btn mat-raised-button\" data-toggle=\"modal\" data-target=\"#addOn\">Buy Add Ons</button>\n          </div>\n        </div>\n      </div>\n      \n      \n        \n        \n        \n        </mat-card>\n        \n        </mat-card>\n      </div>\n      <!--rt aside component start-->\n      <!--rt aside component end-->\n    </div>\n  </div>\n</section>\n<app-footer></app-footer>\n<!-- edit data room -->\n\n<div class=\"modal fade\" id=\"addOn\" tabindex=\"-1\" role=\"dialog\" aria-labelledby=\"exampleModalLabel\" aria-hidden=\"true\">\n  <div class=\"modal-dialog modal-md\" role=\"document\">\n    <div class=\"modal-content\">\n\n      <div class=\"modal-header cdr-modal cdr-h-c\">\n          <h5 class=\"modal-title\">Buy Addon</h5>\n          <button type=\"button\" class=\"close\" data-dismiss=\"modal\" aria-label=\"Close\">\n            <i class=\"material-icons\">&#xE5CD;</i>\n          </button>\n        </div>\n\n      <div class=\"modal-body cr-n-dr edrnl\">\n        <table class=\"table dl-table txt-lf\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n          <thead>\n          <tr>\n            <th>Sr. No.</th>\n            <th>Subscription Name</th>\n            <th>Details</th>\n            <th>Price</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr *ngFor=\"let a Of addOn; let i=index;\">\n            <td>{{ i+1 }}</td>\n            <td>{{ a.addon}}</td>\n            <td>\n                <input type=\"number\" #space (change)=\"addInTotal(a.quantity, a.price, i, addonkey)\" [(ngModel)]=\"a.quantity\" placeholder=\"1GB\" class=\"custom-select mr-sm-2\"> </td>\n            <td>${{a.total}}</td>\n            <!-- <td> {{space.value*100}}$</td> -->\n        </tr>\n        </tbody>\n        </table>\n      </div>\n\n      <div class=\"modal-footer\">\n          <button type=\"button\" class=\"btn btn-secondary\" data-dismiss=\"modal\">Cancel</button>\n          <button type=\"button\" class=\"btn btn-primary\" (click)=\"saveAddOn(addOn)\">Buy Add Ons</button>\n        </div>\n    </div>\n  </div>\n</div>"

