        var start_date;
        var end_date;
        if (this.from_date == "" || this.from_date == null) {
            start_date = "";
        }
        else {
            start_date =
                this.from_date.getFullYear() +
                    "-" +
                    (this.from_date.getMonth() + 1) +
                    "-" +
                    this.from_date.getDate();
        }
        if (this.to_date == "" || this.to_date == null) {
            end_date = "";
        }
