    FolderDetailComponent.prototype.onChangeSelect = function () {
        var _this = this;
        this.toggle = !this.toggle;
        var counter = -1;
        this.all_root_folder_list.forEach(function (folder) {
            folder.selected = _this.toggle;
            _this.all_folder_file_list.push(counter + 1);
        });
        if (this.toggle === true) {
            var all_root_folder = this.all_root_folder_list.filter(function (res) { return res.selected === true; });
            this.selected_folder_list_count = all_root_folder.length;
            if (all_root_folder.length >= 1) {
                this.isActionBar = true;
            }
            else {
                this.selected_folder_list_count = 0;
                this.isActionBar = false;
            }
        }
        else {
            this.isActionBar = false;
            this.selected_folder_list_count = 0;
            var all_root_folder = this.all_root_folder_list.filter(function (res) { return (res.selected = false); });
        }
        this.all_root_folder_list.forEach(function (res) {
            if (res.selected === true) {
                res.isAction = true;
            }
            else {
                res.isAction = false;
            }
        });
    };
    // check box selection
    FolderDetailComponent.prototype.checkbox_value = function (folder, i) {
        folder.selected = folder.selected ? false : true;
        var all_root_folder = this.all_root_folder_list.filter(function (x) { return x.selected === true; });
        this.all_root_folder_list.forEach(function (res) {
            if (res.selected === true) {
                res.isAction = true;
            }
            else {
                res.isAction = false;
            }
        });
        var length = all_root_folder.length;
        if (length >= 1) {
            this.isActionBar = true;
            this.selected_folder_list_count = length;
        }
        else {
            this.isActionBar = false;
            this.selected_folder_list_count = length;
        }
    };
    FolderDetailComponent.prototype.download_all_files = function () {
        var _this = this;
        this.selectedDownload = [];
        this.singleFile = false;
        var all_root_folder = this.all_root_folder_list.filter(function (x) { return x.selected === true; });
        if (all_root_folder.length > 0) {
            all_root_folder.forEach(function (res) {
                _this.selectedDownload.push(res);
            });
            var finalData = {
                data: this.selectedDownload,
                token: localStorage.getItem("token"),
            };
            if (this.selectedDownload.length == 1) {
                if (!this.selectedDownload[0]["is_folder"]) {
                    this.DownloadFiles(this.selectedDownload[0]);
                    this.singleFile = true;
                }
            }
            if (!this.singleFile) {
                this.dataRoomService
                    .bulkDownload(JSON.stringify(finalData))
                    .subscribe(function (ress) {
                    if (ress.name) {
                        var zip_file_path = _this.baseUrl + "/" + ress.path; //put inside "" your server path with file.zip
                        var zip_file_name = ress.name; //put inside "" file name or something
                        var a = document.createElement("a");
                        document.body.appendChild(a);
                        a.href = zip_file_path;
                        a.download = zip_file_name;
                        a.click();
                        document.body.removeChild(a);
                        _this.msg =
                            "Depending on your access, folders & files permitted to be downloaded by the admin will be downloaded shortly from your selection. Please check your Downloads folder on your device.";
                        _this.showInfo();
                    }
                    else {
                        _this.msg =
                            "You dont have access to download this file " + ress.name;
                        _this.showInfo();
                    }
                });
            }
        }
        else {
            this.msg = "Only files can be Download... ";
            this.showInfo();
        }
    };
