    ManageGroupPermissionComponent.prototype.clickUploadPermission = function () {
        var _this = this;
        this.nodes.forEach(function (res) {
            if (Array.isArray(res.children)) {
                var childrens = res.children.filter(function (res) { return res.is_folder === true; });
                if (childrens != undefined) {
                    if (childrens.length > 0) {
                        var upload_children = childrens.filter(function (res) { return res.perm.is_upload === true && res.is_folder == true; });
                        var upload_children_folder = childrens.filter(function (res) { return res.is_folder == true; });
                        if (upload_children.length == upload_children_folder.length) {
                            res.is_upload = true;
                            _this.is_upload_indeterminate = false;
                            // res.is_no_access = false;
                            //res.is_access = false;
                            //res.upload_indeterminate = false
                        }
                        else if (upload_children.length > 0) {
                            // res.upload_indeterminate = true;
                            res.is_upload = false;
                            _this.is_upload_indeterminate = true;
                        }
                        else {
                            _this.is_upload_indeterminate = false;
                        }
                        childrens.forEach(function (ress) {
                            _this.clickUploadSubPermission(ress);
                        });
                    }
                }
            }
        });
        this.AllFilesPermission();
    };
    ManageGroupPermissionComponent.prototype.clickUploadSubPermission = function (res) {
        var _this = this;
        console.log(res);
        var childrens = res.children.filter(function (res) { return res.perm.is_upload === true; });
        if (childrens != undefined) {
            if (childrens.length > 0) {
                var upload_children = childrens.filter(function (res) { return res.perm.is_upload === true; });
                if (upload_children.length == childrens.length) {
                    res.is_upload = true;
                    // res.is_no_access = false;
                    // res.is_access = false;
                }
                else if (upload_children.length > 0) {
                    res.upload_indeterminate = true;
                }
                else {
                    res.upload_indeterminate = false;
                }
                childrens.forEach(function (ress) {
                    _this.clickUploadSubPermission(ress);
                });
            }
        }
    };
