    VotingComponent.prototype.getIcons = function (res, is_folder) {
        if (is_folder == true) {
            var url = "assets/images/ICONS_PNG/folder.png";
            return url;
        }
        else {
            if (res.name.endsWith(".avi") ||
                res.name.endsWith(".mov") ||
                res.name.endsWith(".3gp") ||
                res.name.endsWith(".mpeg") ||
                res.content_type == "video/msvideo" ||
                res.content_type == "video/avi" ||
                res.content_type == "video/x-msvideo") {
                var url = "assets/images/ICONS_PNG/avi.png";
                return url;
            }
            else if (res.content_type == "text/css" || res.name.endsWith(".css")) {
                var url = "assets/images/ICONS_PNG/css.png";
                return url;
            }
            else if (res.content_type == "text/csv" || res.name.endsWith(".csv")) {
                var url = "assets/images/ICONS_PNG/csv.png";
                return url;
            }
            else if (res.content_type == "application/msword" ||
                res.name.endsWith(".doc")) {
                var url = "assets/images/ICONS_PNG/doc.png";
                return url;
            }
            else if (res.name.endsWith(".docx") ||
                res.content_type ==
                    "application/vnd.openxmlformats-officedocument.wordprocessingml.document") {
                var url = "assets/images/ICONS_PNG/docx.png";
                return url;
            }
            else if (res.content_type == "application/vnd.ms-excel" ||
                res.name.endsWith(".xls")) {
                var url = "assets/images/ICONS_PNG/xls.png";
                return url;
            }
            else if (res.content_type ==
                "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" ||
                res.name.endsWith(".xlsx")) {
                var url = "assets/images/ICONS_PNG/xlsx.png";
                return url;
            }
            else if (res.content_type == "application/pdf" ||
                res.name.endsWith(".pdf")) {
                var url = "assets/images/ICONS_PNG/pdf.png";
                return url;
            }
            else if (res.content_type == "audio/mp3" ||
                res.name.endsWith(".mp3") ||
                res.name.endsWith(".wav") ||
                res.name.endsWith(".m4a") ||
                res.name.endsWith(".wma")) {
                var url = "assets/images/ICONS_PNG/mp3.png";
                return url;
            }
            else if (res.content_type == "video/mp4" || res.name.endsWith(".mp4")) {
                var url = "assets/images/ICONS_PNG/mp4.png";
                return url;
            }
            else if (res.content_type == "image/jpeg" ||
                res.content_type == "image/jpg" ||
                res.name.endsWith(".jpg") ||
                res.name.endsWith(".jpeg")) {
                var url = "assets/images/ICONS_PNG/jpg.png";
                return url;
            }
            else if (res.content_type == "image/png" || res.name.endsWith(".png")) {
                var url = "assets/images/ICONS_PNG/png.png";
                return url;
            }
            else if (res.content_type == "text/plain" ||
                res.name.endsWith(".txt")) {
                var url = "assets/images/ICONS_PNG/txt.png";
                return url;
            }
            else {
                var url = "assets/images/ICONS_PNG/default.png";
                return url;
            }
        }
    };
